            return "https://dev-api.example.com"
        case .staging:
            return "https://stag-api.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

class NetworkingLayer {
    
    private let environment: Environment
    private var session: URLSession
    
    init(environment: Environment = .development) {
        self.environment = environment
        self.session = URLSession(configuration: .default)
    }
    
    func get(url: String, completion: @escaping (Data?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.url)/\(url)") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }
            
            guard let data = data else { return }
            completion(data, nil)
        }.resume()
    }
    
    func post(url: String, parameters: [String: Any], completion: @escaping (Data?, Error?) -> Void) {
        guard let url = URL(string: "\(environment.url)/\(url)") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = try? JSONSerialization.data(withJSONObject: parameters, options: [])
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }
            
            guard let data = data else { return }
            completion(data, nil)
        }.resume()
    }
}

